import React, { useState } from 'react';
import { AsyncStorage } from 'react-native';
import CryptoJS from 'crypto-js';

// Import encryption key from config file
import { ENCRYPTION_KEY } from './config';

const EncryptionUtility = () => {
  const [data, setData] = useState('');

  const encryptData = async (value) => {
    try {
      const encrypted = CryptoJS.AES.encrypt(value, ENCRYPTION_KEY).toString();
      await AsyncStorage.setItem('encryptedData', encrypted);
      console.log('Data encrypted and saved');
    } catch (error) {
      console.error('Error encrypting data:', error);
    }
  };

  const decryptData = async () => {
    try {
      const value = await AsyncStorage.getItem('encryptedData');
      if (value) {
        const bytes = CryptoJS.AES.decrypt(value, ENCRYPTION_KEY);
        const originalText = bytes.toString(CryptoJS.enc.Utf8);
        setData(originalText);
        console.log('Data decrypted:', originalText);
      } else {
        console.log('No data found in AsyncStorage');
      }
    } catch (error) {
      console.error('Error decrypting data:', error);
    }
  };

  return (
    <div>
      <button onClick={() => encryptData(JSON.stringify({ name: 'John Doe', age: 30 }))}>Encrypt Data</button>
      <button onClick={decryptData}>Decrypt Data</button>
      <p>Decrypted Data: {data}</p>
    </div>
  );
};

export default EncryptionUtility;